54	   * API key that is being send using the `x-api-key` header.
55	   * It defaults to the `ANTHROPIC_API_KEY` environment variable.
56	   * Only one of `apiKey` or `authToken` is required.
57	   */
58	  apiKey?: string;
59	
60	  /**
61	   * Auth token that is being sent using the `Authorization: Bearer` header.
62	   * It defaults to the `ANTHROPIC_AUTH_TOKEN` environment variable.
63	   * Only one of `apiKey` or `authToken` is required.
64	   */
65	  authToken?: string;
