87	/**
88	 * Create an Anthropic provider instance.
89	 */
90	export function createAnthropic(
91	  options: AnthropicProviderSettings = {},
92	): AnthropicProvider {
93	  const baseURL =
94	    withoutTrailingSlash(
95	      loadOptionalSetting({
96	        settingValue: options.baseURL,
97	        environmentVariableName: 'ANTHROPIC_BASE_URL',
98	      }),
99	    ) ?? 'https://api.anthropic.com/v1';
100	
101	  const providerName = options.name ?? 'anthropic.messages';
102	
103	  // Only error if both are explicitly provided in options
104	  if (options.apiKey && options.authToken) {
105	    throw new InvalidArgumentError({
106	      argument: 'apiKey/authToken',
107	      message:
108	        'Both apiKey and authToken were provided. Please use only one authentication method.',
109	    });
110	  }
111	
112	  const getHeaders = () => {
113	    const authHeaders: Record<string, string> = options.authToken
114	      ? { Authorization: `Bearer ${options.authToken}` }
115	      : {
116	          'x-api-key': loadApiKey({
117	            apiKey: options.apiKey,
118	            environmentVariableName: 'ANTHROPIC_API_KEY',
119	            description: 'Anthropic',
120	          }),
121	        };
122	
123	    return withUserAgentSuffix(
124	      {
125	        'anthropic-version': '2023-06-01',
126	        ...authHeaders,
127	        ...options.headers,
128	      },
129	      `ai-sdk/anthropic/${VERSION}`,
130	    );
131	  };
132	
133	  const createChatModel = (modelId: AnthropicMessagesModelId) =>
134	    new AnthropicMessagesLanguageModel(modelId, {
135	      provider: providerName,
136	      baseURL,
137	      headers: getHeaders,
138	      fetch: options.fetch,
139	      generateId: options.generateId ?? generateId,
140	      supportedUrls: () => ({
141	        'image/*': [/^https?:\/\/.*$/],
142	        'application/pdf': [/^https?:\/\/.*$/],
143	      }),
144	    });
145	
146	  const provider = function (modelId: AnthropicMessagesModelId) {
147	    if (new.target) {
148	      throw new Error(
149	        'The Anthropic model function cannot be called with the new keyword.',
150	      );
151	    }
152	
153	    return createChatModel(modelId);
154	  };
155	
156	  provider.specificationVersion = 'v3' as const;
157	  provider.languageModel = createChatModel;
158	  provider.chat = createChatModel;
159	  provider.messages = createChatModel;
160	
161	  provider.embeddingModel = (modelId: string) => {
162	    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
163	  };
164	  provider.textEmbeddingModel = provider.embeddingModel;
165	  provider.imageModel = (modelId: string) => {
166	    throw new NoSuchModelError({ modelId, modelType: 'imageModel' });
167	  };
168	
169	  provider.tools = anthropicTools;
170	
171	  return provider;
172	}
