describe('createPixelArt', () => {
  it('should create a provider with image model support', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    const model = provider.image('pixelart-standard');
    expect(model).toBeInstanceOf(PixelArtImageModel);
  });

  it('should create image models via imageModel()', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    const model = provider.imageModel('pixelart-hd');
    expect(model).toBeInstanceOf(PixelArtImageModel);
    expect(model.modelId).toBe('pixelart-hd');
  });

  it('should throw NoSuchModelError for languageModel', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    expect(() => provider.languageModel('gpt-4')).toThrow();
  });

  it('should throw NoSuchModelError for embeddingModel', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    expect(() => provider.embeddingModel('embed-v1')).toThrow();
  });

  it('should have specificationVersion v3', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    expect(provider.specificationVersion).toBe('v3');
  });
});

